package com.chaobo.scm.supplier.infrastructure.persistence.item;
import org.apache.ibatis.annotations.*;import java.math.*;import java.time.*;import java.util.*;
@Mapper public interface SupplierItemHistoryQueryMapper {record Condition(long id,long itemId,long supplierId,String sku,String supplierSku,BigDecimal moq,BigDecimal mpq,int days,String unit,LocalDate from,LocalDate to,int version,String type,long operator,OffsetDateTime changedAt){}record Price(long id,long supplierId,String sku,String agreement,String currency,BigDecimal price,BigDecimal tax,LocalDate from,LocalDate to,long contractId,long quoteId,int version,OffsetDateTime createdAt){}@Select("SELECT history_id id,supplier_item_id itemId,supplier_id supplierId,sku_code sku,supplier_sku_code supplierSku,moq,mpq,lead_time_days days,purchase_unit unit,effective_from `from`,effective_to `to`,condition_version version,change_type type,changed_by operator,changed_at changedAt FROM sup_supplier_item_condition_history WHERE supplier_item_id=#{itemId} ORDER BY changed_at DESC")List<Condition> conditions(long itemId);@Select("SELECT snapshot_id id,supplier_id supplierId,sku_code sku,agreement_ref agreement,currency,unit_price price,tax_rate tax,effective_from `from`,effective_to `to`,source_contract_id contractId,source_quote_id quoteId,source_version version,created_at createdAt FROM sup_supplier_item_price_snapshot WHERE supplier_id=#{supplierId} AND sku_code=#{skuCode} ORDER BY effective_from DESC,source_version DESC")List<Price> prices(@Param("supplierId")long supplierId,@Param("skuCode")String skuCode);}
